  1	import React, {
  2	  Dispatch,
  3	  FC,
  4	  KeyboardEvent,
  5	  ReactNode,
  6	  SetStateAction,
  7	  useRef,
  8	  useState,
  9	} from 'react';
 10	
 11	import { useClickOutside } from '@kubevirt-utils/hooks/useClickOutside/useClickOutside';
 12	import { Menu, MenuContent, MenuList, MenuToggle, Popper } from '@patternfly/react-core';
 13	
 14	type MenuHeightsType = {
 15	  [id: string]: number;
 16	};
 17	
 18	type ComposableDrilldownMenuProps = {
 19	  id?: string;
 20	  isOpen: boolean;
 21	  isScrollable?: boolean;
 22	  scrollableMenuIDs?: string[];
 23	  setIsOpen: Dispatch<SetStateAction<boolean>>;
 24	  toggleLabel: ReactNode | string;
 25	};
 26	
 27	const ComposableDrilldownSelect: FC<ComposableDrilldownMenuProps> = ({
 28	  children,
 29	  id = 'rootMenu',
 30	  isOpen,
 31	  isScrollable = false,
 32	  scrollableMenuIDs = [],
 33	  setIsOpen,
 34	  toggleLabel,
 35	}) => {
 36	  const [activeMenu, setActiveMenu] = useState<string>(id);
 37	  const [menuDrilledIn, setMenuDrilledIn] = useState<string[]>([]);
 38	  const [drilldownPath, setDrilldownPath] = useState<string[]>([]);
 39	  const [menuHeights, setMenuHeights] = useState<MenuHeightsType>({});
 40	  const menuRef = useRef<HTMLDivElement>(null);
 41	  const toggleRef = useRef<HTMLDivElement>(null);
 42	
 43	  const onToggleClick = (ev?: React.MouseEvent) => {
 44	    ev?.stopPropagation(); // Stop handleClickOutside from handling
 45	    setIsOpen(!isOpen);
 46	    setMenuDrilledIn([]);
 47	    setDrilldownPath([]);
 48	    setActiveMenu(id);
 49	  };
 50	
 51	  const drillIn = (
 52	    _event: KeyboardEvent | React.MouseEvent,
 53	    fromMenuId: string,
 54	    toMenuId: string,
 55	    pathId: string,
 56	  ) => {
 57	    setMenuDrilledIn([...menuDrilledIn, fromMenuId]);
 58	    setDrilldownPath([...drilldownPath, pathId]);
 59	    setActiveMenu(toMenuId);
 60	  };
 61	
 62	  const drillOut = (_event: KeyboardEvent | React.MouseEvent, toMenuId: string) => {
 63	    setMenuDrilledIn(menuDrilledIn.slice(0, menuDrilledIn.length - 1));
 64	    setDrilldownPath(drilldownPath.slice(0, drilldownPath.length - 1));
 65	    setActiveMenu(toMenuId);
 66	  };
 67	
 68	  const setHeight = (menuId: string, height: number) => {
 69	    if (!menuHeights[menuId] || (menuId !== id && menuHeights[menuId] !== height)) {
 70	      setMenuHeights((prev) => ({
 71	        ...prev,
 72	        [menuId]: height,
 73	      }));
 74	    }
 75	  };
 76	
 77	  useClickOutside([menuRef], onToggleClick);
 78	
 79	  return (
 80	    <Popper
 81	      popper={
 82	        <Menu
 83	          activeMenu={activeMenu}
 84	          containsDrilldown
 85	          drilldownItemPath={drilldownPath}
 86	          drilledInMenus={menuDrilledIn}
 87	          id={id}
 88	          isScrollable={isScrollable || scrollableMenuIDs.includes(activeMenu)}
 89	          onDrillIn={drillIn}
 90	          onDrillOut={drillOut}
 91	          onGetMenuHeight={setHeight}
 92	          ref={menuRef}
 93	        >
 94	          <MenuContent menuHeight={`${menuHeights[activeMenu]}px`}>
 95	            <MenuList>{children}</MenuList>
 96	          </MenuContent>
 97	        </Menu>
 98	      }
 99	      trigger={
100	        <MenuToggle isExpanded={isOpen} isFullWidth onClick={onToggleClick} ref={toggleRef}>
101	          {toggleLabel}
102	        </MenuToggle>
103	      }
104	      appendTo={document.getElementById('tab-modal')}
105	      direction="up"
106	      isVisible={isOpen}
107	    />
108	  );
109	};
110	
111	export default ComposableDrilldownSelect;

